const BASE_URL = "http://127.0.0.1:8000";



export const createUser = async (user) => {
  const res = await fetch(`${BASE_URL}/users/`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(user),
  });
  return res.json();
};

export const deleteUser = async (id) => {
    await fetch(`http://127.0.0.1:8000/users/${id}`, {
        method: "DELETE",
    });
};

export const updateUser = async (id, user) => {
  const res = await fetch(`http://127.0.0.1:8000/users/${id}`, {
    method: "PUT",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify(user),
  });

  return res.json();
};


const getAuthHeaders = () => {
  const token = localStorage.getItem("token");

  return {
    "Content-Type": "application/json",
    Authorization: `Bearer ${token}`,
  };
};


export const loginUser = async (formData) => {
  try {
    const response = await axios.post("http://127.0.0.1:8000/users/login", formData, {
      headers: {
        "Content-Type": "application/x-www-form-urlencoded",
      },
    });
    return response.data; // This returns the {access_token: "..."} object
  } catch (error) {
    console.error("API Error:", error.response?.data);
    return null; // Return null so 'res' isn't undefined
  }
};


export const getUsers = async () => {           
  const res = await fetch(`${BASE_URL}/users`, {
    headers: getAuthHeaders(),
  });

  return res.json();
};


const token = localStorage.getItem("token");

fetch("http://127.0.0.1:8000/users", {
  headers: {
    Authorization: `Bearer ${token}`,
  },
});
